# Cache for JWKS public keys
_jwks_cache = None
_jwks_cache_time = None
JWKS_CACHE_TTL_SECONDS = 300


class AuthenticationError(Exception):
    """Raised when JWT validation fails."""
    def __init__(self, message, status_code=401):
        self.message = message
        self.status_code = status_code
        super().__init__(self.message)


def get_jwks_public_keys():
    """Fetch and cache JWKS public keys for RS256 verification."""
    global _jwks_cache, _jwks_cache_time

    now = datetime.now(timezone.utc)
    if (
        _jwks_cache is not None
        and _jwks_cache_time is not None
        and (now - _jwks_cache_time).total_seconds() < JWKS_CACHE_TTL_SECONDS
    ):
        return _jwks_cache

    jwks_url = app.config["JWKS_URL"]
    if not jwks_url:
        return None

    try:
        response = requests.get(jwks_url, timeout=10)
        response.raise_for_status()
        jwks = response.json()

        public_keys = {}
        for key_data in jwks.get("keys", []):
            kid = key_data.get("kid")
            if kid:
                public_key = jwt.algorithms.RSAAlgorithm.from_jwk(key_data)
                public_keys[kid] = public_key

        _jwks_cache = public_keys
        _jwks_cache_time = now
        logger.info("Successfully refreshed JWKS public keys.")
        return public_keys
    except Exception as e:
        logger.error(f"Failed to fetch JWKS keys: {e}")
        if _jwks_cache is not None:
            return _jwks_cache
        raise AuthenticationError("Unable to verify token: key service unavailable", 503)


def get_verification_key(token_headers):
    """Get the appropriate key for verifying the JWT signature."""
    algorithm = app.config["JWT_ALGORITHM"]

    if algorithm.startswith("RS") or algorithm.startswith("ES"):
        # Asymmetric algorithm - use public key from JWKS
        public_keys = get_jwks_public_keys()
        if not public_keys:
            raise AuthenticationError("JWKS not configured for asymmetric algorithm")

        kid = token_headers.get("kid")
        if not kid:
            raise AuthenticationError("Token missing 'kid' header")

        key = public_keys.get(kid)
        if not key:
            # Try refreshing the cache in case keys were rotated
            global _jwks_cache_time
            _jwks_cache_time = None
            public_keys = get_jwks_public_keys()
            key = public_keys.get(kid)
            if not key:
                raise AuthenticationError("Token signed with unknown key")
        return key

    elif algorithm.startswith("HS"):
        # Symmetric algorithm - use shared secret
        secret = app.config["JWT_SECRET_KEY"]
        if not secret:
            raise AuthenticationError("JWT secret key not configured", 500)
        return secret

    else:
        raise AuthenticationError(f"Unsupported algorithm: {algorithm}", 500)


def decode_and_validate_token(token):
    """
    Decode and FULLY VALIDATE a JWT token.

    This performs:
    - Signature verification (ensures token hasn't been tampered with)
    - Expiration check (exp claim)
    - Not-before check (nbf claim)
    - Issuer validation (iss claim) if configured
    - Audience validation (aud claim) if configured
    """
    try:
        # First, read headers without verification to get kid
        unverified_headers = jwt.get_unverified_header(token)

        # Ensure the algorithm in the token matches what we expect
        # This prevents algorithm confusion attacks
        expected_algorithm = app.config["JWT_ALGORITHM"]
        token_algorithm = unverified_headers.get("alg")
        if token_algorithm != expected_algorithm:
            raise AuthenticationError(
                f"Token algorithm '{token_algorithm}' does not match "
                f"expected '{expected_algorithm}'"
            )

        # Get the appropriate verification key
        verification_key = get_verification_key(unverified_headers)

        # Build decode options
        decode_options = {
            "verify_signature": True,  # ALWAYS verify signature
            "verify_exp": True,        # ALWAYS check expiration
            "verify_nbf": True,        # Check not-before
            "verify_iat": True,        # Check issued-at
            "require": ["exp", "iat", "sub"],  # Required claims
        }

        decode_kwargs = {
            "algorithms": [expected_algorithm],  # Only allow expected algorithm
            "options": decode_options,
        }

        # Add issuer validation if configured
        if app.config.get("JWT_ISSUER"):
            decode_kwargs["issuer"] = app.config["JWT_ISSUER"]

        # Add audience validation if configured
        if app.config.get("JWT_AUDIENCE"):
            decode_kwargs["audience"] = app.config["JWT_AUDIENCE"]

        # Decode with FULL verification
        claims = jwt.decode(token, verification_key, **decode_kwargs)

        return claims

    except jwt.ExpiredSignatureError:
        raise AuthenticationError("Token has expired")
    except jwt.InvalidIssuerError:
        raise AuthenticationError("Invalid token issuer")
    except jwt.InvalidAudienceError:
        raise AuthenticationError("Invalid token audience")
    except jwt.ImmatureSignatureError:
        raise AuthenticationError("Token is not yet valid")
    except jwt.InvalidAlgorithmError:
        raise AuthenticationError("Invalid token algorithm")
    except jwt.DecodeError:
        raise AuthenticationError("Token could not be decoded")
    except jwt.InvalidTokenError as e:
        raise AuthenticationError(f"Invalid token: {str(e)}")
    except AuthenticationError:
        raise
    except Exception as e:
        logger.error(f"Unexpected error during token validation: {e}")
        raise AuthenticationError("Token validation failed", 500)


def extract_token_from_header():
    """Extract Bearer token from Authorization header."""
    auth_header = request.headers.get("Authorization")
    if not auth_header:
        raise AuthenticationError("Missing Authorization header")

    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise AuthenticationError("Authorization header must be: Bearer <token>")

    return parts[1]


def require_auth(f):
    """Decorator that requires a valid JWT token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = extract_token_from_header()
        claims = decode_and_validate_token(token)

        # Store validated claims in Flask's request context
        g.jwt_claims = claims
        g.user_id = claims.get("sub")
        g.user_email = claims.get("email")
        g.user_roles = claims.get("roles", [])

        logger.info(
            f"Authenticated request from user={g.user_id} "
            f"roles={g.user_roles} "
            f"path={request.path}"
        )

        return f(*args, **kwargs)
    return decorated


def require_roles(*required_roles):
    """Decorator that requires specific roles in the JWT claims."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            user_roles = set(g.get("user_roles", []))
            required = set(required_roles)

            if not required.intersection(user_roles):
                logger.warning(
                    f"Authorization denied for user={g.user_id} "
                    f"has_roles={user_roles} "
                    f"required_roles={required}"
                )
                return jsonify({
                    "error": "Forbidden",
                    "message": "Insufficient permissions"
                }), 403

            return f(*args, **kwargs)
        return decorated
    return decorator


def forward_to_backend(service_path, method="GET", data=None):
    """Forward request to backend service with validated user claims as headers."""
    backend_url = f"{app.config['BACKEND_BASE_URL']}{service_path}"

    # Forward validated claims as trusted internal headers
    headers = {
        "X-Authenticated-User-Id": g.user_id or "",
        "X-Authenticated-User-Email": g.user_email or "",
        "X-Authenticated-User-Roles": ",".join(g.user_roles),
        "X-Request-Id": request.headers.get("X-Request-Id", ""),
        "Content-Type": request.content_type or "application/json",
    }

    try:
        response = requests.request(
            method=method,
            url=backend_url,
            headers=headers,
            json=data,
            params=request.args,
            timeout=30,
        )
        return (response.content, response.status_code, dict(response.headers))
    except requests.exceptions.ConnectionError:
        logger.error(f"Backend service unavailable: {backend_url}")
        return jsonify({"error": "Service unavailable"}), 503
    except requests.exceptions.Timeout:
        logger.error(f"Backend service timeout: {backend_url}")
        return jsonify({"error": "Service timeout"}), 504


